pub fn sys_exec(path: *const u8, mut args: *const usize) -> isize {
    let token = current_user_token();
    let path = translate_str(token, path);
        let mut args_vec: Vec<String> = Vec::new();
        loop {
            let arg_str_ptr = *translated_ref(token, args);
            if arg_str_ptr == 0 {
                break;
            }
            args_vec.push(translate_str(token, arg_str_ptr as *const u8));
            unsafe {
                args = args.add(1);
            }
        }
        if let Some(data) = get_app_data_by_name(path.as_str()) {
            let task = current_task().unwrap();
            task.exec(data, args_vec);
            0 // Actually never return 0
        } else {
            // Search in filesystem
            if let Ok(mnt_inode) = ROOT_FILESYSTEM.mountpoint_root_inode().find(true, "mnt") {
                if let Ok(program_inode) = mnt_inode.find(false, &path) {
                    // Read elf data
                    let size = program_inode.metadata().unwrap().size;
                    let mut buf = Vec::new();
                    // println!("Program size: {}", size);
                    buf.resize(size, 0);
                    program_inode.read_at(0, &mut buf).unwrap();
                    let task = current_task().unwrap();
                    task.exec(&buf, args_vec);
                    0
                } else {
                    -1
                }
            } else {
                -1
            }
            // test_system_fatfs();
            // -1
        }
}

pub fn sys_waitpid(pid: isize, exit_code_ptr: *mut i32) -> isize {
    let task = current_task().unwrap();

    let mut inner = task.inner_exclusive_access();
    if !inner
        .children
        .iter()
        .any(|p| pid == -1 || pid as usize == p.getpid())
    {
        return -1; // no zombie process found
    }
    let pair = inner.children.iter().enumerate().find(|(_, p)| {
        p.inner_exclusive_access().is_zombie() && (pid == -1 || pid as usize == p.getpid())
    });
    if let Some((idx, _)) = pair {
        let child = inner.children.remove(idx);
        assert_eq!(Arc::strong_count(&child), 1);
        let found_pid = child.getpid();
        let exit_code = child.inner_exclusive_access().exit_code;
        if exit_code_ptr as usize != 0 {
            if translate_memcopy(
                inner.get_user_token(),
                exit_code_ptr as usize as *const u8,
                &exit_code,
            )
            .is_err()
            {
                error!("trans_memcopy on wait failed! {:#x}", exit_code_ptr as usize);
            }
        }
        found_pid as isize
    } else {
        drop(inner);
        waitpid_suspend_current_and_run_next(pid, exit_code_ptr as usize, 0);
        -1
    }
}

pub fn sys_wait_waitpid(task: Arc<TaskControlBlock>, pid: isize, exit_code_ptr: *mut i32) -> isize {
    let mut inner = task.inner_exclusive_access();
    if !inner
        .children
        .iter()
        .any(|p| pid == -1 || pid as usize == p.getpid())
    {
        return -1; // no zombie process found
    }
    let pair = inner.children.iter().enumerate().find(|(_, p)| {
        p.inner_exclusive_access().is_zombie() && (pid == -1 || pid as usize == p.getpid())
    });
    if let Some((idx, _)) = pair {
        let child = inner.children.remove(idx);
        assert_eq!(Arc::strong_count(&child), 1);
        let found_pid = child.getpid();
        let exit_code = child.inner_exclusive_access().exit_code;
        if exit_code_ptr as usize != 0 {
            if translate_memcopy(
                inner.get_user_token(),
                exit_code_ptr as usize as *const u8,
                &exit_code,
            )
            .is_err()
            {
                error!("trans_memcopy on wait failed! {:#x}", exit_code_ptr as usize);
            }
        }
        found_pid as isize
    } else {
        -2
    }
}

