impl Seek for VirtIOBlock {
    fn seek(&mut self, pos: fatfs::SeekFrom) -> Result<u64, Self::Error> {
        match pos {
            fatfs::SeekFrom::Start(value) => {
                self.sector = value as usize / SECTOR_SIZE;
                self.offset = value as usize % SECTOR_SIZE;
                Ok(value)
            }
            fatfs::SeekFrom::Current(value) => {
                let new_value = ((self.sector * SECTOR_SIZE + self.offset) as i64 + value) as usize;
                self.sector = new_value / SECTOR_SIZE;
                self.offset = value as usize % SECTOR_SIZE;
                Ok(new_value as u64)
            }
            fatfs::SeekFrom::End(_) => {
                panic!("Not implemented");
            }
        }
    }
}


impl Read for VirtIOBlock {
    fn read(&mut self, buf: &mut [u8]) -> Result<usize, Self::Error> {
        // prefetch for whole block
        // from sector to ceil(current_position + buf.len)
        let current_position = self.sector * SECTOR_SIZE + self.offset;
        let max_position = current_position + buf.len();
        let max_block_id = max_position / SECTOR_SIZE;
        // we fetch self.offset to max_block_id
        let mut buffer = vec![0u8; SECTOR_SIZE*(max_block_id-self.sector+1)];
        if self.virt_driver.exclusive_access().read_blocks(self.sector, &mut buffer).is_err() {
            Err(IOError::EofError)
        }else {
            buf.copy_from_slice(&buffer[self.offset..self.offset+buf.len()]);
            // update pointer
            self.sector = (current_position + buf.len()) / SECTOR_SIZE;
            self.offset = (current_position + buf.len()) % SECTOR_SIZE;
            Ok(buf.len())
        }

    }
}

impl Write for VirtIOBlock {
    fn write(&mut self, buf: &[u8]) -> Result<usize, Self::Error> {
        // prefetch for whole block
        // from sector to ceil(current_position + buf.len)
        let current_position = self.sector * SECTOR_SIZE + self.offset;
        let max_position = current_position + buf.len();
        let max_block_id = max_position / SECTOR_SIZE;
        // we fetch self.offset to max_block_id
        let mut buffer = vec![0u8; SECTOR_SIZE*(max_block_id-self.sector+1)];
        let mut virtio_driver = self.virt_driver.exclusive_access();
        if virtio_driver.read_blocks(self.sector, &mut buffer).is_err() {
            Err(IOError::EofError)
        }else {
            buffer[self.offset..self.offset+buf.len()].copy_from_slice(buf);
            // sync to block
            if virtio_driver.write_blocks(self.sector, &buffer).is_ok() {
                self.sector = (current_position + buf.len()) / SECTOR_SIZE;
                self.offset = (current_position + buf.len()) % SECTOR_SIZE;
                Ok(buf.len())
            }else {
                Err(IOError::EofError)
            }
        }
    }
    fn flush(&mut self) -> Result<(), Self::Error> {
        Ok(()) // do nothing because we flush it
    }
}

