unsafe impl Hal for VirtIOAllocator {
    fn dma_alloc(
        pages: usize,
        _direction: virtio_drivers::BufferDirection,
    ) -> (virtio_drivers::PhysAddr, core::ptr::NonNull<u8>) {
        // 必须分配连续的内存页面
        println!("dma_alloc");
        let mut ppn_base = PhysPageNum(0);
        for i in 0..pages {
            let frame = frame_alloc().unwrap();
            if i == 0 {
                ppn_base = frame.ppn;
            }
            assert_eq!(frame.ppn.0, ppn_base.0 + i, "No contiguous page allocated.");
            println!("Allocated PPN={}", &frame.ppn.0);
            QUEUE_FRAMES.exclusive_access().push(frame);
        }
        println!("ppn_base={}", ppn_base.0);
        (
            PhysAddr::from(ppn_base).into(),
            core::ptr::NonNull::new(PhysAddr::from(ppn_base).0 as *mut u8)
                .expect("should not be null"),
        )
    }

    unsafe fn dma_dealloc(
        paddr: virtio_drivers::PhysAddr,
        _vaddr: core::ptr::NonNull<u8>,
        pages: usize,
    ) -> i32 {
        println!("Dealloc dma");
        let ppn_base: PhysPageNum = paddr.into();
        let mut queue = QUEUE_FRAMES.exclusive_access();
        let mut block_id = MAX;
        queue
            .iter()
            .enumerate()
            .filter_map(
                |(i, page)| {
                    if page.ppn == ppn_base {
                        Some(i)
                    } else {
                        None
                    }
                },
            )
            .for_each(|i| {
                block_id = i;
            });
        if block_id == MAX {
            0
        } else {
            queue.drain(block_id..(block_id + pages));
            0
        }
    }

    unsafe fn mmio_phys_to_virt(paddr: virtio_drivers::PhysAddr, _size: usize) -> NonNull<u8> {
        println!("mmio_phys");
        core::ptr::NonNull::new(paddr as *mut _).unwrap()
    }

    unsafe fn share(
        buffer: NonNull<[u8]>,
        _direction: virtio_drivers::BufferDirection,
    ) -> virtio_drivers::PhysAddr {
        // println!("share {}", PhysPageNum::from(buffer.as_ptr() as *mut u8 as usize).0);
        // buffer.as_ptr() as *mut u8 as usize
        assert_ne!(buffer.len(), 0);
        // To ensure that the driver is handling and unsharing buffers properly, allocate a new
        // buffer and copy to it if appropriate.
        let mut shared_buffer = u8::new_box_slice_zeroed(buffer.len());
        if let BufferDirection::DriverToDevice | BufferDirection::Both = _direction {
            unsafe {
                buffer
                    .as_ptr()
                    .cast::<u8>()
                    .copy_to(shared_buffer.as_mut_ptr(), buffer.len());
            }
        }
        let vaddr = Box::into_raw(shared_buffer) as *mut u8 as usize;
        // Nothing to do, as the host already has access to all memory.
        vaddr
    }

    unsafe fn unshare(
        paddr: virtio_drivers::PhysAddr,
        buffer: NonNull<[u8]>,
        direction: virtio_drivers::BufferDirection,
    ) {
        // println!("unshare");
        // // no op
        assert_ne!(buffer.len(), 0);
        assert_ne!(paddr, 0);
        let vaddr = paddr as *mut u8;
        let shared_buffer = unsafe {
            Box::from_raw(ptr::slice_from_raw_parts_mut(
                vaddr as *mut u8,
                buffer.len(),
            ))
        };
        if let BufferDirection::DeviceToDriver | BufferDirection::Both = direction {
            unsafe {
                buffer
                    .as_ptr()
                    .cast::<u8>()
                    .copy_from(shared_buffer.as_ptr(), buffer.len());
            }
        }
    }
}

